mapper.select:
SELECT id, queue_id, user_id, enabled, last_assigned_at, created_at, updated_at
FROM ticket_queue_member
WHERE id = #{id}

SELECT id, queue_id, user_id, enabled, last_assigned_at, created_at, updated_at
FROM ticket_queue_member
WHERE queue_id = #{queueId}
  AND user_id = #{userId}

SELECT id, queue_id, user_id, enabled, last_assigned_at, created_at, updated_at FROM ticket_queue_member WHERE queue_id = #{queueId}
AND enabled = #{enabled}
ORDER BY CASE WHEN last_assigned_at IS NULL THEN 0 ELSE 1 END ASC, last_assigned_at ASC, id ASC

mapper.update:
UPDATE ticket_queue_member
SET enabled = #{enabled}
WHERE id = #{id}

UPDATE ticket_queue_member
SET last_assigned_at = CURRENT_TIMESTAMP
WHERE id = #{id}
